import React from 'react';
import styles from '../../styles/erpPage.module.css';

export interface CatalogLegacyCodeSuffixProps {
  code?: string | null;
  legacyCode?: string | null;
  testIdPrefix: string;
}

/** «Mã cũ:» suffix when migrate legacyCode differs from current code (Step 2w). */
export const CatalogLegacyCodeSuffix: React.FC<CatalogLegacyCodeSuffixProps> = ({
  code,
  legacyCode,
  testIdPrefix,
}) => {
  if (!legacyCode || legacyCode === code) return null;
  return (
    <span className={styles.legacyCodeSuffix} data-testid={`${testIdPrefix}-legacy-code-suffix`}>
      Mã cũ: {legacyCode}
    </span>
  );
};
